svg.script:
(function(){
  var districts = document.querySelectorAll('.district');
  districts.forEach(function(el){
    el.addEventListener('click', function(){
      districts.forEach(function(d){ d.classList.remove('active'); });
      el.classList.add('active');
      var name = el.getAttribute('data-name');
      var id   = el.getAttribute('id');
      var evt = new CustomEvent('districtClick', { detail:{ id:id, name:name }, bubbles:true });
      el.dispatchEvent(evt);
    });
    el.addEventListener('keydown', function(e){
      if(e.key==='Enter'||e.key===' '){ el.click(); }
    });
  });
})();
